// PLC payload
var waterLevel = msg.payload.Water_Level;
var motorState = msg.payload.Motor_State;

// Sensor key mapping (must match sensors_new table)
var WATER_LEVEL_SENSOR_KEY = 125;
var MOTOR_STATE_SENSOR_KEY = 126;

// Prepare multiple insert rows
msg.topic = `
    INSERT INTO sensor_data (sensor_ID, data_value, log_time)
    VALUES (?, ?, NOW()),
           (?, ?, NOW())
`;

msg.payload = [
    WATER_LEVEL_SENSOR_KEY, waterLevel,
    MOTOR_STATE_SENSOR_KEY, motorState
];

return msg;

var rows = msg.payload; // Data array from MySQL node
var outWater = [], outMotor = [], outTemp = [], outHum = [], 
    outLight = [], outOcc = [], outDist = [], outSmoke = [], outFan = [];

rows.forEach(function(row) {
    var point = {
        x: new Date(row.log_time).getTime(),
        y: row.data_value
    };

    // Mapping based on your provided sensor table
    switch(row.sensor_ID) {
        case 125: outWater.push(point); break; // Water_Level
        case 126: outMotor.push(point); break; // Motor_State
        case 118: outTemp.push(point);  break; // TemperatureDHT
        case 119: outHum.push(point);   break; // Humidity
        case 120: outLight.push(point); break; // LightPercent
        case 121: outOcc.push(point);   break; // Occupancy
        case 122: outDist.push(point);  break; // Distance
        case 123: outSmoke.push(point); break; // SmokePercent
        case 124: outFan.push(point);   break; // FanState
    }
});

// Return 9 payloads in the exact order of your flow's output pins
return [
    { payload: [{ series: ["Water Level"], data: [outWater] }] },
    { payload: [{ series: ["Motor Status"], data: [outMotor] }] },
    { payload: [{ series: ["Temperature"], data: [outTemp] }] },
    { payload: [{ series: ["Humidity"], data: [outHum] }] },
    { payload: [{ series: ["Light"], data: [outLight] }] },
    { payload: [{ series: ["Occupancy"], data: [outOcc] }] },
    { payload: [{ series: ["Distance"], data: [outDist] }] },
    { payload: [{ series: ["Smoke"], data: [outSmoke] }] },
    { payload: [{ series: ["Fan State"], data: [outFan] }] }
];

